var userRepository = {
  /**
   * 根据用户名查找用户
   */
  findByUsername(username) {
    const db2 = getDb();
    const result = db2.select().from(users).where(eq(users.username, username)).limit(1).get();
    return result;
  },
  /**
   * 根据 ID 查找用户
   */
  findById(id) {
    const db2 = getDb();
    const result = db2.select().from(users).where(eq(users.id, id)).limit(1).get();
    return result;
  },
  /**
   * 创建用户
   */
  create(data) {
    const db2 = getDb();
    const result = db2.insert(users).values({
      ...data,
      isActive: data.isActive ?? true
    }).returning().get();
    return result;
  },
  /**
   * 更新用户
   */
  update(id, data) {
    const db2 = getDb();
    const result = db2.update(users).set(data).where(eq(users.id, id)).returning().get();
    return result;
  },
  /**
   * 删除用户
   */
  delete(id) {
    const db2 = getDb();
    const result = db2.delete(users).where(eq(users.id, id)).run();
    return result.changes > 0;
  },
  /**
   * 获取所有用户
   */
  findAll() {
    const db2 = getDb();
    return db2.select().from(users).all();
  },
  /**
   * 根据用户名和密码查找用户（用于登录验证）
   */
  findActiveByUsername(username) {
    const db2 = getDb();
    const result = db2.select().from(users).where(and(eq(users.username, username), eq(users.isActive, true))).limit(1).get();
    return result;
  },
  /**
   * 查找或创建用户（upsert）
   */
  findOrCreate(username, data) {
    const existing = this.findByUsername(username);
    if (existing) {
      return this.update(existing.id, { ...data, isActive: true });
    }
    return this.create({ username, ...data });
  }
};

