// src/routes/dbHealth.ts
var DEFAULT_PORT_TIMEOUT = 1500;
var DEFAULT_POSTGRES_PORT = 5432;
var DEFAULT_MYSQL_PORT = 3306;
var tryTcpConnect = (host, port, timeoutMs = DEFAULT_PORT_TIMEOUT) => new Promise((resolve2) => {
  const socket = import_node_net.default.createConnection({ host, port });
  const done = (result) => {
    socket.removeAllListeners();
    socket.destroy();
    resolve2(result);
  };
  socket.setTimeout(timeoutMs);
  socket.once("connect", () => done(true));
  socket.once("timeout", () => done(false));
  socket.once("error", () => done(false));
});
var buildHealthData = (ok, configured, mode, detail) => ({
  ok,
  configured,
  mode,
  detail,
  vectorStore: getVectorStoreHealth()
});
var checkSqliteFile = async (filePath) => {
  try {
    await import_promises.default.access(filePath);
    return buildHealthData(true, true, "sqlite", `SQLite \uFFFD\u013C\uFFFD\uFFFD\u0277\uFFFD\uFFFD\uFFFD: ${filePath}`);
  } catch {
    return buildHealthData(false, true, "sqlite", `SQLite \uFFFD\u013C\uFFFD\uFFFD\uFFFD\uFFFD\u0277\uFFFD\uFFFD\uFFFD: ${filePath}`);
  }
};
var getDefaultPort = (protocol) => {
  if (protocol.startsWith("postgres")) {
    return DEFAULT_POSTGRES_PORT;
  }
  if (protocol.startsWith("mysql")) {
    return DEFAULT_MYSQL_PORT;
  }
  return 0;
};
var dbHealthRoute = async (app2) => {
  app2.get(
    "/db/health",
    {
      schema: {
        tags: ["System"],
        summary: "Database connectivity health check",
        response: {
          200: {
            type: "object",
            required: ["success", "data", "timestamp"],
            properties: {
              success: { type: "boolean", const: true },
              data: {
                type: "object",
                required: ["ok", "configured", "mode", "detail", "vectorStore"],
                properties: {
                  ok: { type: "boolean" },
                  configured: { type: "boolean" },
                  mode: { type: "string" },
                  detail: { type: "string" },
                  vectorStore: {
                    type: "object",
                    required: ["ok", "provider", "detail"],
                    properties: {
                      ok: { type: "boolean" },
                      provider: { type: "string", const: "sqlite-vec" },
                      detail: { type: "string" },
                      extensionPath: { type: "string" }
                    }
                  }
                }
              },
              message: { type: "string" },
              timestamp: { type: "string", format: "date-time" }
            }
          }
        }
      }
    },
    async () => {
      const databaseUrl = process.env.DATABASE_URL;
      if (!databaseUrl) {
        return success(
          buildHealthData(
            false,
            false,
            "unconfigured",
            "DATABASE_URL \u03B4\uFFFD\uFFFD\uFFFD\xE3\uFFFD\uFFFD\uFFFD\uFFFD\uFFFD\uFFFD\uFFFD\uFFFD\uFFFD\uFFFD\uFFFD\uFFFD\uFFFD\u012C\uFFFD\uFFFD\u02B9\uFFFD\xF1\uFFFD\uFFFD\uFFFD SQLite\uFFFD\uFFFD"
          )
        );
      }
      if (databaseUrl.startsWith("file:")) {
        const filePath = databaseUrl.replace("file:", "");
        return success(await checkSqliteFile(filePath));
      }
      if (databaseUrl.endsWith(".db") || databaseUrl.endsWith(".sqlite")) {
        const dbPath = import_node_path.default.resolve(databaseUrl);
        return success(await checkSqliteFile(dbPath));
      }
      try {
        const parsed = new URL(databaseUrl);
        const host = parsed.hostname;
        if (!host) {
          throw new Error("\u0231\uFFFD\uFFFD\uFFFD\uFFFD\uFFFD\uFFFD\uFFFD\uFFFD");
        }
        let port = Number(parsed.port);
        if (!port) {
          port = getDefaultPort(parsed.protocol);
        }
        if (!port) {
          return success(
            buildHealthData(
              false,
              true,
              parsed.protocol.replace(":", ""),
              `\uFFFD\u07B7\uFFFD\uFFFD\u01B6\u03F6\u02FF\uFFFD: ${databaseUrl}`
            )
          );
        }
        const reachable = await tryTcpConnect(host, port);
        return success(
          buildHealthData(
            reachable,
            true,
            parsed.protocol.replace(":", ""),
            reachable ? `\uFFFD\uFFFD\uFFFD\u077F\uFFFD\uFFFD\uFFFD\u05B7\uFFFD\uFFFD\uFFFD\uFFFD\uFFFD\uFFFD: ${host}:${port}` : `\uFFFD\uFFFD\uFFFD\u077F\uFFFD\uFFFD\uFFFD\u05B7\uFFFD\uFFFD\uFFFD\u0274\uFFFD: ${host}:${port}`
          )
        );
      } catch (error2) {
        return success(
          buildHealthData(
            false,
            true,
            "unknown",
            error2 instanceof Error ? `\uFFFD\uFFFD\uFFFD\u077F\uFFFD URL \uFFFD\uFFFD\uFFFD\uFFFD\u02A7\uFFFD\uFFFD: ${error2.message}` : "\uFFFD\uFFFD\uFFFD\u077F\uFFFD URL \uFFFD\uFFFD\uFFFD\uFFFD\u02A7\uFFFD\uFFFD"
          )
        );
      }
    }
  );
};
var dbHealth_default = dbHealthRoute;

