var authenticateUser = (username, password) => {
  const user = userRepository.findActiveByUsername(username);
  if (!user) {
    return null;
  }
  if (!isSameHash(user.passwordHash, hashPassword(password))) {
    return null;
  }
  return {
    id: user.id,
    username: user.username,
    role: user.role
  };
};
var changeUserPassword = (userId, currentPassword, nextPassword) => {
  const user = userRepository.findById(userId);
  if (!user || !user.isActive) {
    return { ok: false, reason: "USER_NOT_FOUND" };
  }
  const currentPasswordHash = hashPassword(currentPassword);
  const nextPasswordHash = hashPassword(nextPassword);
  if (!isSameHash(user.passwordHash, currentPasswordHash)) {
    return { ok: false, reason: "INVALID_CURRENT_PASSWORD" };
  }
  if (isSameHash(user.passwordHash, nextPasswordHash)) {
    return { ok: false, reason: "PASSWORD_UNCHANGED" };
  }
  userRepository.update(user.id, {
    passwordHash: nextPasswordHash
  });
  return {
    ok: true,
    user: {
      id: user.id,
      username: user.username,
      role: user.role
    }
  };
};
var JWT_SECRET = process.env.JWT_SECRET || "uichat-rag-test-secret-key-change-in-production";
var JWT_EXPIRES_IN = "7d";
var createAccessToken = (user) => {
  return import_jsonwebtoken.default.sign(
    {
      sub: String(user.id),
      username: user.username,
      role: user.role
    },
    JWT_SECRET,
    { expiresIn: JWT_EXPIRES_IN }
  );
};
var verifyAccessToken = (token) => {
  try {
    const decoded = import_jsonwebtoken.default.verify(token, JWT_SECRET);
    return {
      id: Number(decoded.sub),
      username: decoded.username,
      role: decoded.role
    };
  } catch {
    return null;
  }
};
var requireAuth = async (request, reply) => {
  const authHeader = request.headers.authorization;
  if (!authHeader || !authHeader.startsWith("Bearer ")) {
    return reply.code(401).send({ ok: false, message: "Missing auth token" });
  }
  const token = authHeader.slice(7);
  const user = verifyAccessToken(token);
  if (!user) {
    return reply.code(401).send({ ok: false, message: "Invalid auth token" });
  }
  request.authUser = user;
};

