var proxyOllamaRoute = async (app2) => {
  app2.post(
    "/proxy/ollama/chat",
    {
      attachValidation: true,
      schema: {
        body: {
          type: "object",
          required: ["messages"],
          properties: {
            messages: {
              type: "array",
              items: {
                type: "object",
                required: ["role", "parts"],
                properties: {
                  role: {
                    type: "string",
                    enum: ["system", "user", "assistant"]
                  },
                  parts: {
                    type: "array",
                    items: {
                      type: "object",
                      additionalProperties: true
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    async (request, reply) => {
      const validationResponse = handleValidationError(request, reply);
      if (validationResponse) {
        return validationResponse;
      }
      try {
        const payload = request.body;
        const messages = normalizeMessages(payload.messages);
        if (messages.length === 0) {
          return createErrorResponse(reply, "No valid chat messages provided");
        }
        const modelConfig = modelConfigRepository.findDefaultByType("llm");
        if (!modelConfig) {
          return createErrorResponse(reply, "No LLM model configured");
        }
        if (!modelConfig.providerCode || !modelConfig.remoteModelId) {
          return createErrorResponse(
            reply,
            "LLM model has no provider or remote model assigned"
          );
        }
        const provider = providerConnectionRepository.findByCode(
          modelConfig.providerCode
        );
        if (!provider) {
          return createErrorResponse(
            reply,
            `Provider "${modelConfig.providerCode}" not found`
          );
        }
        const apiKey = decryptSecret(provider.apiKeyEncrypted);
        const modelParams = parseModelParams(modelConfig.params);
        const providerCode = modelConfig.providerCode;
        const remoteModelId = modelConfig.remoteModelId;
        const streamText = () => {
          switch (providerCode) {
            case "ollama":
              return streamOllamaChat({
                baseUrl: provider.baseUrl ?? "",
                apiKey,
                model: remoteModelId,
                messages,
                params: modelParams
              });
            case "lmstudio":
            case "openai":
              return streamOpenAICompatibleChat({
                baseUrl: provider.baseUrl ?? "",
                apiKey,
                model: remoteModelId,
                messages,
                params: modelParams
              });
            default:
              throw new Error(
                `Unsupported provider "${providerCode}"`
              );
          }
        };
        reply.raw.setHeader("Cache-Control", "no-cache, no-transform");
        reply.raw.setHeader("Connection", "keep-alive");
        reply.type("text/event-stream; charset=utf-8");
        return reply.send(createUiMessageStream(streamText));
      } catch (err) {
        app2.log.error({ err }, "[proxy-ollama] chat failed");
        const message = err instanceof Error ? err.message : "Unknown error";
        return reply.code(500).send(error(message, ErrorCodes.INTERNAL_ERROR));
      }
    }
  );
};
var proxy_ollama_default = proxyOllamaRoute;

// src/routes/account.ts
var accountRoute = async (app2) => {
  app2.post(
    "/account/change-password",
    {
      preHandler: requireAuth,
      attachValidation: true,
      schema: {
        tags: ["Auth"],
        summary: "Change current user password",
        description: "Validate the current password and update the authenticated user's password.",
        security: [{ bearerAuth: [] }],
        body: {
          type: "object",
          additionalProperties: false,
          required: ["currentPassword", "newPassword"],
          properties: {
            currentPassword: { type: "string", minLength: 1 },
            newPassword: { type: "string", minLength: 6 }
          }
        },
        response: {
          200: {
            type: "object",
            required: ["success", "data", "timestamp"],
            properties: {
              success: { type: "boolean", const: true },
              data: {
                type: "object",
                required: ["user"],
                properties: {
                  user: {
                    type: "object",
                    required: ["id", "username", "role"],
                    properties: {
                      id: { type: "number" },
                      username: { type: "string" },
                      role: { type: "string", enum: ["admin", "user"] }
                    }
                  }
                }
              },
              message: { type: "string" },
              timestamp: { type: "string", format: "date-time" }
            }
          },
          400: {
            type: "object",
            required: ["success", "message", "timestamp"],
            properties: {
              success: { type: "boolean", const: false },
              message: { type: "string" },
              code: { type: "string" },
              errors: { type: "array", items: {} },
              timestamp: { type: "string", format: "date-time" }
            }
          },
          401: {
            type: "object",
            required: ["success", "message", "timestamp"],
            properties: {
              success: { type: "boolean", const: false },
              message: { type: "string" },
              code: { type: "string" },
              timestamp: { type: "string", format: "date-time" }
            }
          }
        }
      }
    },
    async (request, reply) => {
      const validationResponse = handleValidationError(request, reply);
      if (validationResponse) {
        return validationResponse;
      }
      const authUser = request.authUser;
      const payload = request.body;
      if (!authUser) {
        return reply.code(401).send(error("Unauthorized", ErrorCodes.UNAUTHORIZED));
      }
      if (!payload.currentPassword.trim() || !payload.newPassword.trim() || payload.currentPassword === payload.newPassword) {
        return reply.code(400).send(error("Invalid request payload", ErrorCodes.VALIDATION_ERROR));
      }
      const result = changeUserPassword(
        authUser.id,
        payload.currentPassword,
        payload.newPassword
      );
      if (!result.ok) {
        if (result.reason === "INVALID_CURRENT_PASSWORD") {
          return reply.code(401).send(
            error("Current password is incorrect", ErrorCodes.UNAUTHORIZED)
          );
        }
        return reply.code(400).send(
          error(
            "New password must be different",
            ErrorCodes.VALIDATION_ERROR
          )
        );
      }
      return success({ user: result.user }, "Password updated successfully");
    }
  );
};
