var toModelConfigResponse = (row) => ({
  id: row.id,
  type: row.type,
  name: row.name,
  providerCode: row.providerCode ?? null,
  remoteModelId: row.remoteModelId ?? null,
  params: JSON.parse(row.params),
  isDefault: row.isDefault,
  createdAt: row.createdAt,
  updatedAt: row.updatedAt
});
var toParamTemplateResponse = (row) => ({
  key: row.paramKey,
  label: row.paramLabel,
  type: row.paramType,
  step: row.step ?? void 0,
  options: row.options ? JSON.parse(row.options) : void 0,
  defaultValue: JSON.parse(row.defaultValue)
});
var modelConfigService = {
  getDefaultConfig(type) {
    const config = modelConfigRepository.findDefaultByType(type);
    return config ? toModelConfigResponse(config) : null;
  },
  getAllDefaultConfigs() {
    return modelConfigRepository.findAllDefaults().map(toModelConfigResponse);
  },
  updateDefaultConfig(type, data) {
    const current = modelConfigRepository.findDefaultByType(type);
    if (!current) {
      return null;
    }
    const mergedParams = data.params ? {
      ...JSON.parse(current.params),
      ...data.params
    } : JSON.parse(current.params);
    const updated = modelConfigRepository.updateDefault(type, {
      name: data.name ?? current.name,
      params: JSON.stringify(mergedParams),
      providerCode: data.providerCode !== void 0 ? data.providerCode : current.providerCode,
      remoteModelId: data.remoteModelId !== void 0 ? data.remoteModelId : current.remoteModelId
    });
    return updated ? toModelConfigResponse(updated) : null;
  },
  getParamTemplates(type) {
    const rows = type ? modelParamTemplateRepository.findByModelType(type) : modelParamTemplateRepository.findAll();
    const result = {
      llm: [],
      embedding: [],
      rerank: []
    };
    for (const row of rows) {
      result[row.modelType].push(toParamTemplateResponse(row));
    }
    return result;
  }
};

