async function modelConfigRoutes(fastify) {
  fastify.get(
    "/models",
    {
      schema: {
        tags: ["Model Settings"],
        summary: "Get active role model configs",
        description: "Return the current effective default configs for llm, embedding, and rerank.",
        operationId: "getActiveRoleModelConfigs",
        response: {
          200: successEnvelope2({
            type: "array",
            items: modelConfigSchema
          }),
          500: errorEnvelope2
        }
      }
    },
    async (_request, reply) => {
      try {
        const configs = modelConfigService.getAllDefaultConfigs();
        return success(configs);
      } catch (err) {
        fastify.log.error(err);
        return reply.code(500).send(error("Failed to get models", ErrorCodes.INTERNAL_ERROR));
      }
    }
  );
  fastify.get(
    "/models/:type/config",
    {
      schema: {
        tags: ["Model Settings"],
        summary: "Get active config by role",
        description: "Return the current effective config for a specific role.",
        operationId: "getActiveRoleModelConfigByType",
        params: {
          type: "object",
          properties: {
            type: { type: "string", enum: modelTypeEnum }
          },
          required: ["type"]
        },
        response: {
          200: successEnvelope2(modelConfigSchema),
          404: errorEnvelope2,
          500: errorEnvelope2
        }
      }
    },
    async (request, reply) => {
      try {
        const { type } = request.params;
        const config = modelConfigService.getDefaultConfig(type);
        if (!config) {
          return reply.code(404).send(error("Config not found", ErrorCodes.NOT_FOUND));
        }
        return success(config);
      } catch (err) {
        fastify.log.error(err);
        return reply.code(500).send(error("Failed to get config", ErrorCodes.INTERNAL_ERROR));
      }
    }
  );
  fastify.put(
    "/models/:type/config",
    {
      schema: {
        tags: ["Model Settings"],
        summary: "Update active config params by role",
        description: "Update the current effective role config. Typically used by the main settings page to save params.",
        operationId: "updateActiveRoleModelConfigByType",
        params: {
          type: "object",
          properties: {
            type: { type: "string", enum: modelTypeEnum }
          },
          required: ["type"]
        },
        body: {
          type: "object",
          additionalProperties: false,
          properties: {
            name: { type: "string" },
            params: { type: "object", additionalProperties: true }
          }
        },
        response: {
          200: successEnvelope2(modelConfigSchema),
          404: errorEnvelope2,
          500: errorEnvelope2
        }
      }
    },
    async (request, reply) => {
      try {
        const { type } = request.params;
        const { name, params } = request.body;
        const config = modelConfigService.updateDefaultConfig(type, {
          name,
          params
        });
        if (!config) {
          return reply.code(404).send(error("Config not found", ErrorCodes.NOT_FOUND));
        }
        return success(config, "Config updated successfully");
      } catch (err) {
        fastify.log.error(err);
        return reply.code(500).send(error("Failed to update config", ErrorCodes.INTERNAL_ERROR));
      }
    }
  );
  fastify.get(
    "/models/param-templates",
    {
      schema: {
        tags: ["Model Settings"],
        summary: "Get param templates",
        description: "Return backend-defined parameter templates for llm, embedding, and rerank.",
        operationId: "getRoleModelParamTemplates",
        querystring: {
          type: "object",
          properties: {
            type: { type: "string", enum: modelTypeEnum }
          }
        },
        response: {
          200: successEnvelope2({
            type: "object",
            required: ["llm", "embedding", "rerank"],
            properties: {
              llm: { type: "array", items: paramTemplateItemSchema },
              embedding: { type: "array", items: paramTemplateItemSchema },
              rerank: { type: "array", items: paramTemplateItemSchema }
            }
          }),
          500: errorEnvelope2
        }
      }
    },
    async (request, reply) => {
      try {
        const { type } = request.query;
        const templates = modelConfigService.getParamTemplates(
          type
        );
        return success(templates);
      } catch (err) {
        fastify.log.error(err);
        return reply.code(500).send(error("Failed to get param templates", ErrorCodes.INTERNAL_ERROR));
      }
    }
  );
}
