var trimTrailingSlash = (value) => value.replace(/\/+$/, "");
var normalizeOpenAICompatibleBaseUrl2 = (baseUrl) => {
  const normalized = trimTrailingSlash(baseUrl);
  if (normalized.endsWith("/v1")) {
    return normalized;
  }
  return `${normalized}/v1`;
};
var fetchJson = async (url, init) => {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), 15e3);
  try {
    const response = await fetch(url, {
      ...init,
      signal: controller.signal
    });
    if (!response.ok) {
      const text2 = await response.text();
      throw new Error(text2 || `Request failed with status ${response.status}`);
    }
    return await response.json();
  } finally {
    clearTimeout(timeout);
  }
};
var listProviderModels = async (providerCode, baseUrl, apiKey) => {
  if (providerCode === "ollama") {
    const url2 = `${trimTrailingSlash(baseUrl)}/api/tags`;
    const result2 = await fetchJson(url2);
    return (result2.models ?? []).map((model) => ({
      id: model.name,
      name: model.name,
      raw: model
    }));
  }
  const normalizedBaseUrl = normalizeOpenAICompatibleBaseUrl2(baseUrl);
  const url = `${normalizedBaseUrl}/models`;
  const headers = {};
  if (apiKey) {
    headers.Authorization = `Bearer ${apiKey}`;
  }
  const result = await fetchJson(
    url,
    { headers }
  );
  return (result.data ?? []).map((model) => ({
    id: model.id,
    name: model.id,
    raw: model
  }));
};
